mapper.select:
SELECT
ID
FROM
T_BUS_CARGO_INFO
WHERE
COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND CARGO_OWNER_ID = #{cargoOwnerId,jdbcType=BIGINT}

    AND CARGO_AGENT_ID = #{cargoAgentId,jdbcType=BIGINT}


    AND CARGO_AGENT_ID IS NULL

AND CARGO_CODE = #{cargoCode,jdbcType=VARCHAR}

    AND ID != #{id,jdbcType=BIGINT}


    AND SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}


    AND TRADE_TYPE = #{tradeType,jdbcType=VARCHAR}


    AND PACKING_CODE = #{packingCode,jdbcType=VARCHAR}


    AND IS_CLEAR = #{isClear,jdbcType=VARCHAR}

mapper.insert:
begin
INSERT INTO T_PRD_PORT_STORAGE(ID, COMPANY_ID, COMPANY_NAME, CARGO_INFO_ID, STOREHOUSE_ID, STOREHOUSE_NAME, REGION_ID, REGION_NAME, MASS_ID, MASS_NAME, QUANTITY, TON, CLEAN_MASS_SIGN, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, CLEAN_MASS_BY, CLEAN_MASS_BY_NAME, CLEAN_MASS_TIME) VALUES ( #{item.id, jdbcType=BIGINT}, #{item.companyId, jdbcType=BIGINT}, #{item.companyName, jdbcType=VARCHAR}, #{item.cargoInfoId, jdbcType=BIGINT}, #{item.storehouseId, jdbcType=BIGINT}, #{item.storehouseName, jdbcType=VARCHAR}, #{item.regionId, jdbcType=BIGINT}, #{item.regionName, jdbcType=VARCHAR}, #{item.massId, jdbcType=BIGINT}, #{item.massName, jdbcType=VARCHAR}, #{item.quantity, jdbcType=INTEGER}, #{item.ton, jdbcType=DECIMAL}, #{item.cleanMassSign, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now, jdbcType=TIMESTAMP}, #{item.cleanMassBy, jdbcType=BIGINT}, #{item.cleanMassByName, jdbcType=VARCHAR}, #{item.cleanMassTime, jdbcType=TIMESTAMP});
end;

